  ('social-worker-moex-05793', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於專注（attending）的敘述，何者錯誤？', '["是指社會工作人員協助案主聚焦於案主最想解決的問題面向", "呈現出對案主的尊重與興趣", "必須觀察並解讀案主的口語、非口語訊息", "適當時候可以保持沉默"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
